INSERT OR IGNORE INTO citations VALUES('X0008','S0001','60',NULL,'Chapter 2 genealogy of the Ashiqloo branch','Mohammad Hossein Khan had five sons, including Nabi Khan Gharagozloo.','Supports parentage and branch.');
INSERT OR IGNORE INTO citations VALUES('X0009','S0001','119',NULL,'Chapter 3, section 3-2-8','Thousands of Gharagozloo troops served in the Herat campaign under Nabi Khan; Abdollah Khan, holding the rank of yavar, supported his troops.','Herat deployment and ranks.');
INSERT OR IGNORE INTO citations VALUES('X0010','S0001','119',NULL,'Same passage','In 1255 AH British forces attacked Bushehr; fifty Gharagozloo soldiers guarded the port, but the small Iranian force could not prevent occupation.','Bushehr guard.');
INSERT OR IGNORE INTO citations VALUES('X0011','S0001','120',NULL,'Herat fortress fighting','Abdollah Khan was wounded and consequently obtained the rank of sarhang; Gharagozloo troops worked to capture the fortress and open its gates.','Promotion and combat role.');
INSERT OR IGNORE INTO citations VALUES('X0012','S0001','120',NULL,'Herat fortress fighting','Shir Ali Khan repeatedly climbed the fortress wall and attempted to plant the victory flag; he received a robe of honor and decoration.','Individual valor.');
INSERT OR IGNORE INTO citations VALUES('X0013','S0001','120',NULL,'Herat casualties','Rashid Khan, a colonel of the Mokhberan regiment, was wounded in the leg; Nabi Khan was severely wounded and died shortly afterward.','Wounds and death.');
INSERT OR IGNORE INTO citations VALUES('X0014','S0001','121',NULL,'Aftermath of Herat fighting','By order of Mohammad Shah, Nabi Khan and other Gharagozloo dead were transferred for burial in Mashhad.','Burial.');
INSERT OR IGNORE INTO citations VALUES('X0015','S0001','128',NULL,'Administrative section on Mahmoud Khan','Mahmoud Khan was the son of Nabi Khan and a descendant of Mohammad Hossein Khan Ashiqloo; after Nabi Khan’s death at Herat Mohammad Shah issued a decree concerning him.','Genealogy and succession context.');
